+// MockMailClient implements MailClient interface for testing
+type MockMailClient struct {
+	Available     bool
+	ProjKey       string
+	Agents        []agentmail.Agent
+	Inboxes       map[string][]agentmail.InboxMessage
+	ListAgentsErr error
+	FetchInboxErr error
+}
+
+func (m *MockMailClient) IsAvailable() bool {
+	return m.Available
+}
