+func (m *MockMailClient) ProjectKey() string {
+	return m.ProjKey
+}
+
+func (m *MockMailClient) ListProjectAgents(ctx context.Context, projectKey string) ([]agentmail.Agent, error) {
+	if m.ListAgentsErr != nil {
